import { NativeModules, Platform } from 'react-native';

const InAppPurchase = NativeModules.InAppPurchase;

class PaymentModule {
  constructor() {
    this.products = [];
  }

  async initialize() {
    await InAppPurchase.initialize();
    this.products = await InAppPurchase.getProducts();
  }

  async purchase(productId) {
    const purchase = await InAppPurchase.purchase(productId);
    return purchase;
  }

  async restorePurchases() {
    const purchases = await InAppPurchase.restorePurchases();
    return purchases;
  }

  getCurrencyCode() {
    return Platform.OS === 'ios' ? InAppPurchase.getCurrencyCode() : 'USD';
  }

  getProducts() {
    return this.products;
  }
}

export default new PaymentModule();